#!/usr/bin/env bash
set -euo pipefail
PW="${SUDO_PW:-kutay123}"
log() { echo "[$(date +%H:%M:%S)] $*"; }
log "=== STEP 10: flows deploy (wired YZ UI) ==="
mkdir -p ~/.node-red
cp ~/.node-red/flows.json ~/.node-red/flows.json.bak.$(date +%s) 2>/dev/null || true
python3 << 'PYEOF'
import base64, json, pathlib
flows = json.loads(base64.b64decode("").decode("utf-8"))
path = pathlib.Path.home() / ".node-red/flows.json"
path.write_text(json.dumps(flows, indent=4, ensure_ascii=False) + "\n")
print("  flows OK — link+template nodes wired")
PYEOF
echo "${PW}" | sudo -S systemctl restart nodered
sleep 8
log "=== STEP 10 BITTI — Deploy tikla: http://172.20.10.5:1880 ==="
